create extension if not exists pgcrypto;
create table if not exists public.kc_user_profiles(user_id uuid primary key references auth.users(id) on delete cascade,role text not null default 'editor');
create table if not exists public.kc_categories(id uuid primary key default gen_random_uuid(),slug text unique not null,icon text not null,name_en text not null,name_bn text not null,sort_order int default 0,is_active boolean default true);
create table if not exists public.kc_articles(id uuid primary key default gen_random_uuid(),category_slug text not null references public.kc_categories(slug),title_en text not null,title_bn text not null,content_en text not null,content_bn text not null,keywords_en text default '',keywords_bn text default '',is_popular boolean default false,status text default 'published',sort_order int default 0,view_count bigint default 0);
create table if not exists public.kc_announcements(id uuid primary key default gen_random_uuid(),title_en text not null,title_bn text not null,body_en text default '',body_bn text default '',level text default 'info',is_active boolean default true,sort_order int default 0);
create table if not exists public.kc_service_status(id uuid primary key default gen_random_uuid(),service_key text unique not null,label_en text not null,label_bn text not null,state text default 'normal',sort_order int default 0);
create table if not exists public.kc_support_channels(id uuid primary key default gen_random_uuid(),channel_key text unique not null,label_en text not null,label_bn text not null,url text not null,icon text default '💬',is_active boolean default true,sort_order int default 0);
alter table public.kc_user_profiles enable row level security;alter table public.kc_categories enable row level security;alter table public.kc_articles enable row level security;alter table public.kc_announcements enable row level security;alter table public.kc_service_status enable row level security;alter table public.kc_support_channels enable row level security;
create or replace function public.kc_is_editor() returns boolean language sql stable security definer as $$select exists(select 1 from public.kc_user_profiles where user_id=auth.uid() and role in ('admin','editor'));$$;
drop policy if exists "kc categories public" on public.kc_categories;create policy "kc categories public" on public.kc_categories for select using(is_active=true);
drop policy if exists "kc articles public" on public.kc_articles;create policy "kc articles public" on public.kc_articles for select using(status='published');
drop policy if exists "kc announcements public" on public.kc_announcements;create policy "kc announcements public" on public.kc_announcements for select using(is_active=true);
drop policy if exists "kc status public" on public.kc_service_status;create policy "kc status public" on public.kc_service_status for select using(true);
drop policy if exists "kc support public" on public.kc_support_channels;create policy "kc support public" on public.kc_support_channels for select using(is_active=true);
drop policy if exists "kc categories editor" on public.kc_categories;create policy "kc categories editor" on public.kc_categories for all using(public.kc_is_editor()) with check(public.kc_is_editor());
drop policy if exists "kc articles editor" on public.kc_articles;create policy "kc articles editor" on public.kc_articles for all using(public.kc_is_editor()) with check(public.kc_is_editor());
drop policy if exists "kc announcements editor" on public.kc_announcements;create policy "kc announcements editor" on public.kc_announcements for all using(public.kc_is_editor()) with check(public.kc_is_editor());
drop policy if exists "kc status editor" on public.kc_service_status;create policy "kc status editor" on public.kc_service_status for all using(public.kc_is_editor()) with check(public.kc_is_editor());
drop policy if exists "kc support editor" on public.kc_support_channels;create policy "kc support editor" on public.kc_support_channels for all using(public.kc_is_editor()) with check(public.kc_is_editor());